local G = DYCLegendary local require = G.DYCModRequire local enchantmentSystem = require( "dyc_enchantments" ) local GetEncDisplayName = enchantmentSystem.GetDisplayName local function GetEnchanter(self) return self.dycEnchanter end local function CanEnchant(enchanter, object) if enchanter.canEnchantFn then return enchanter.canEnchantFn(enchanter.inst, object) end local prefab = object.prefab if prefab and next(enchanter.allowedPrefabs) then return enchanter.allowedPrefabs[prefab] end return true end local function Enchant(enchanter, object) if not CanEnchant(enchanter, object) then return false end if enchanter.enchantments then local number = 0x0 for _, data in pairs(enchanter.enchantments) do if data.names and #data.names > 0x0 and (not data.failTag or #object:GetEnchantmentsWithTag(data.failTag) <= 0x0) then local name = data.names[math.random(0x1, #data.names)] local enc = object:AddEnchantment(name, true) if enc then number = number + 0x1 end end end return number > 0x0 end if enchanter.enchantFn then return enchanter.enchantFn(enchanter.inst, object) end end local function GetDisplayString(enchanter) local enchantments = enchanter.enchantments local str = "" if enchantments then for k, encData in pairs(enchantments) do if encData then local encName = encData.names and encData.names[0x1] if encName then local encStr = GetEncDisplayName(encName) str = str..(#str > 0x0 and "," or "" )..(encStr or "" ) end end end end if #str > 0x0 then return str end end local function SetEnchanter(self, data) if data and type(data) == "table" then self.dycEnchanter = {} local enchanter = self.dycEnchanter enchanter.inst = self.inst enchanter.allowedPrefabs = {} if data.allowedPrefabs then for k, v in pairs(data.allowedPrefabs) do enchanter.allowedPrefabs[v] = true end end enchanter.time = data.time enchanter.enchantments = data.enchantments enchanter.CanEnchant = CanEnchant enchanter.Enchant = Enchant enchanter.enchantFn = data.enchantFn enchanter.canEnchantFn = data.canEnchantFn enchanter.GetDisplayString = GetDisplayString else self.dycEnchanter = nil end end local function OnSave(self, ...) local data = nil if self.dycOldOnSave then data = self.dycOldOnSave(self, ...) end if not data then data = {} end local enchanter = self:GetEnchanter() data.enchanterEnchantments = enchanter and enchanter.enchantments return data end local function OnLoad(self, data, ...) if data then if data.enchanterEnchantments then local enchanter = self:GetEnchanter() if enchanter then enchanter.enchantments = data.enchanterEnchantments end end end if self.dycOldOnLoad then return self.dycOldOnLoad(self, data, ...) end end local function DYCInvItem(self) self.SetEnchanter = SetEnchanter self.GetEnchanter = GetEnchanter self.dycOldOnSave = self.OnSave self.OnSave = OnSave self.dycOldOnLoad = self.OnLoad self.OnLoad = OnLoad end return DYCInvItem 